class SecureCache:
    def __init__(self, redis_client, encryption_key: Optional[str] = None):
        self.redis = redis_client
        self.encryption_key = encryption_key or secrets.token_hex(32)
        
    def _hash_key(self, key: str) -> str:
        return hashlib.sha256(key.encode()).hexdigest()
    
    def _encrypt_value(self, value: str) -> str:
        try:
            from cryptography.fernet import Fernet
            key = hashlib.sha256(self.encryption_key.encode()).digest()
            key_b64 = base64.urlsafe_b64encode(key)
            cipher = Fernet(key_b64)
            return cipher.encrypt(value.encode()).decode()
        except ImportError:
            import base64
            return base64.b64encode(value.encode()).decode()
    
    def _decrypt_value(self, encrypted_value: str) -> str:
        try:
            from cryptography.fernet import Fernet
            key = hashlib.sha256(self.encryption_key.encode()).digest()
            key_b64 = base64.urlsafe_b64encode(key)
            cipher = Fernet(key_b64)
            return cipher.decrypt(encrypted_value.encode()).decode()
        except ImportError:
            import base64
            return base64.b64decode(encrypted_value.encode()).decode()
    
    def set_with_ttl(self, key: str, value: Any, ttl_seconds: int, encrypt: bool = True):
        try:
            hashed_key = self._hash_key(key)
            
            if isinstance(value, (dict, list)):
                value = json.dumps(value)
            else:
                value = str(value)
            
            if encrypt:
                value = self._encrypt_value(value)
            
            self.redis.setex(hashed_key, ttl_seconds, value)
            logger.info(f"Stored key with TTL: {ttl_seconds}s")
            return True
        except Exception as e:
            logger.error(f"Error setting value: {e}")
            return False
    
    def get(self, key: str, decrypt: bool = True) -> Optional[str]:
        try:
            hashed_key = self._hash_key(key)
            value = self.redis.get(hashed_key)
            
            if value is None:
                return None
            
            if decrypt:
                value = self._decrypt_value(value)
            
            try:
                return json.loads(value)
            except json.JSONDecodeError:
                return value
        except Exception as e:
            logger.error(f"Error getting value: {e}")
            return None
    
    def delete(self, key: str) -> bool:
        try:
            hashed_key = self._hash_key(key)
            result = self.redis.delete(hashed_key)
            return result > 0
        except Exception as e:
            logger.error(f"Error deleting key: {e}")
            return False
    
    def exists(self, key: str) -> bool:
        try:
            hashed_key = self._hash_key(key)
            return self.redis.exists(hashed_key) > 0
        except Exception as e:
            logger.error(f"Error checking key existence: {e}")
            return False
    
    def get_ttl(self, key: str) -> int:
        try:
            hashed_key = self._hash_key(key)
            return self.redis.ttl(hashed_key)
        except Exception as e:
            logger.error(f"Error getting TTL: {e}")
            return -1


class SessionManager:
    def __init__(self, secure_cache: SecureCache):
        self.cache = secure_cache
        self.session_ttl = 3600
        self.refresh_token_ttl = 604800
    
    def create_session(self, user_id: str, metadata: Optional[Dict] = None) -> str:
        session_token = secrets.token_urlsafe(32)
        session_key = f"session:{session_token}"
        
        session_data = {
            "user_id": user_id,
            "created_at": str(timedelta(seconds=0)),
            "metadata": metadata or {}
        }
        
        self.cache.set_with_ttl(session_key, session_data, self.session_ttl, encrypt=True)
        logger.info(f"Created session for user: {user_id}")
        return session_token
    
    def get_session(self, session_token: str) -> Optional[Dict]:
        session_key = f"session:{session_token}"
        return self.cache.get(session_key, decrypt=True)
    
    def refresh_session(self, session_token: str) -> bool:
        session_data = self.get_session(session_token)
        if session_data:
            session_key = f"session:{session_token}"
            self.cache.set_with_ttl(session_key, session_data, self.session_ttl, encrypt=True)
            return True
        return False
    
    def invalidate_session(self, session_token: str) -> bool:
        session_key = f"session:{session_token}"
        return self.cache.delete(session_key)
    
    def create_refresh_token(self, user_id: str) -> str:
        refresh_token = secrets.token_urlsafe(48)
        refresh_key = f"refresh:{refresh_token}"
        
        refresh_data = {
            "user_id": user_id,
            "created_at": str(timedelta(seconds=0))
        }
        
        self.cache.set_with_ttl(refresh_key, refresh_data, self.refresh_token_ttl, encrypt=True)
        return refresh_token
    
    def validate_refresh_token(self, refresh_token: str) -> Optional[str]:
        refresh_key = f"refresh:{refresh_token}"
        refresh_data = self.cache.get(refresh_key, decrypt=True)
        if refresh_data:
            return refresh_data.get("user_id")
        return None


class APIKeyManager:
    def __init__(self, secure_cache: SecureCache):
        self.cache = secure_cache
        self.api_key_ttl = 31536000
    
    def create_api_key(self, user_id: str, scopes: list, ttl: Optional[int] = None) -> str:
        api_key = f"sk_{secrets.token_urlsafe(32)}"
        api_key_hash = hashlib.sha256(api_key.encode()).hexdigest()
        key_storage = f"apikey:{api_key_hash}"
        
        key_data = {
            "user_id": user_id,
            "scopes": scopes,
            "created_at": str(timedelta(seconds=0)),
            "active": True
        }
        
        ttl_value = ttl or self.api_key_ttl
        self.cache.set_with_ttl(key_storage, key_data, ttl_value, encrypt=True)
        logger.info(f"Created API key for user: {user_id}")
        return api_key
    
    def validate_api_key(self, api_key: str) -> Optional[Dict]:
        api_key_hash = hashlib.sha256(api_key.encode()).hexdigest()
        key_storage = f"apikey:{api_key_hash}"
        
        key_data = self.cache.get(key_storage, decrypt=True)
        if key_data and key_data.get("active"):
            return key_data
        return None
    
    def revoke_api_key(self, api_key: str) -> bool:
        api_key_hash = hashlib.sha256(api_key.encode()).hexdigest()
        key_storage = f"apikey:{api_key_hash}"
        
        key_data = self.cache.get(key_storage, decrypt=True)
        if key_data:
            key_data["active"] = False
            remaining_ttl = self.cache.get_ttl(key_storage)
            if remaining_ttl > 0:
                self.cache.set_with_ttl(key_storage, key_data, remaining_ttl, encrypt=True)
                return True
        return False
    
    def list_user_api_keys(self, user_id: str) -> list:
        keys = []
        try:
            for key in self.cache.redis.scan_iter(match="*apikey:*", count=100):
                key_data = self.cache.get(key, decrypt=True)
                if key_data and key_data.get("user_id") == user_id:
                    keys.append({
                        "scopes": key_data.get("scopes"),
                        "active": key_data.get("active"),
                        "created_at": key_data.get("created_at")
                    })
        except Exception as e:
            logger.error(f"Error listing API keys: {e}")
        return keys


class CachingMicroservice:
    def __init__(self, connection_config: Dict[str, Any], encryption_key: Optional[str] = None):
        self.connection_manager = RedisConnectionManager(**connection_config)
        self.redis_client = self.connection_manager.get_client()
        self.secure_cache = SecureCache(self.redis_client, encryption_key)
        self.session_manager = SessionManager(self.secure_cache)
        self.api_key_manager = APIKeyManager(self.secure_cache)
    
    def health_check(self) -> Dict[str, Any]:
        is_healthy = self.connection_manager.ping()
        return {
            "status": "healthy" if is_healthy else "unhealthy",
            "redis_connected": is_healthy,
            "connection_type": self.connection_manager.connection_type
        }
    
    def cache_user_data(self, user_id: str, data: Dict, ttl: int = 3600):
        key = f"user:{user_id}:data"
        return self.secure_cache.set_with_ttl(key, data, ttl, encrypt=True)
    
    def get_user_data(self, user_id: str) -> Optional[Dict]:
        key = f"user:{user_id}:data"
        return self.secure_cache.get(key, decrypt=True)
    
    def cache_rate_limit(self, identifier: str, limit: int, window: int):
        key = f"ratelimit:{identifier}"
        try:
            current = self.redis_client.incr(key)
            if current == 1:
                self.redis_client.expire(key, window)
            return current <= limit
        except Exception as e:
            logger.error(f"Rate limit error: {e}")
            return True


